     2|import { getIVXRuntimeInfo } from '@/lib/runtime-environment';
     3|import { SUPABASE_HOST_HINT } from '@/lib/supabase';
     4|import { IVX_CANONICAL_API_BASE_URL } from '@/lib/ivx-supabase-client';
     5|
     6|/**
     7| * Build/bundle identity surfaced on the IVX Diagnostics screen so the owner can
     8| * confirm — on the live device — which frontend bundle is actually running and
     9| * that it is NOT a stale cached bundle.
    10| *
    11| * Values are sourced from `app.config.ts` `extra` (baked into the JS bundle at
    12| * build time), so they change only when a NEW bundle is built and shipped. If
    13| * the device shows an OLD marker after reload, the bundle is stale.
    14| *
    15| * Production builds must never show `local` for the Git SHA or `unknown` for the
    16| * API environment. If the required `extra` values are missing, the build is
    17| * considered unidentified and diagnostics will report that explicitly.
    18| */
    19|export interface IVXBuildInfo {
    20|  /** Human build marker, e.g. IVX_BUNDLE_2026_07_15_BUILD_14_OWNER_SESSION_STABILIZED. */
    21|  buildMarker: string;
    22|  /** ISO timestamp the bundle marker was set. */
    23|  buildTimestamp: string;
    24|  /** Watchdog patch identifier (bumped whenever the watchdog/owner-auth logic changes). */
    25|  watchdogPatchVersion: string;
    26|  /** Frontend deploy marker, distinct from the backend /health marker. */
    27|  frontendDeployMarker: string;
    28|  /** App version from app.config.ts. */
    29|  appVersion: string;
    30|  /** Short commit hash from app.config.ts extra.sourceCommitSha. */
    31|  commitShort: string;
    32|  /** Full commit hash from app.config.ts extra.sourceCommitSha. */
    33|  commitFull: string;
    34|  /** Epoch ms when this JS bundle first executed (proves a fresh reload). */
    35|  bundleBootEpochMs: number;
    36|  /** Runtime environment label: development, staging, or production. */
    37|  environment: 'development' | 'staging' | 'production';
    38|  /** Runtime kind: expo-go, dev-client, standalone, web, or unknown. */
    39|  runtimeKind: string;
    40|  /** Canonical API base URL the app is wired to. */
    41|  apiBaseUrl: string;
    42|  /** Redacted Supabase project identifier (host) for diagnostics. */
    43|  supabaseProjectHint: string;
    44|  /** EAS project ID from app.config.ts, redacted in display. */
    45|  easProjectId: string | null;
    46|  /** True when the build identity values are present and valid. */
    47|  isIdentified: boolean;
    48|  /** Human-readable reason if the build is unidentified. */
    49|  unidentifiedReason: string | null;
    50|}
    51|
    52|type ExtraShape = {
    53|  buildMarker?: unknown;
    54|  buildTimestamp?: unknown;
    55|  watchdogPatchVersion?: unknown;
    56|  frontendDeployMarker?: unknown;
    57|  sourceCommitSha?: unknown;
    58|  eas?: { projectId?: unknown };
    59|};
    60|
    61|function readString(value: unknown, fallback: string): string {
    62|  return typeof value === 'string' && value.length > 0 ? value : fallback;
    63|}
    64|
    65|function readEnvironment(): IVXBuildInfo['environment'] {
    66|  const runtime = getIVXRuntimeInfo();
    67|  if (typeof __DEV__ !== 'undefined' && __DEV__) {
    68|    return 'development';
    69|  }
    70|  if (runtime.isStandalone) {
    71|    return 'production';
    72|  }
    73|  if (runtime.isExpoGo || runtime.isDevRuntime) {
    74|    return 'development';
    75|  }
    76|  return 'production';
    77|}
    78|
    79|function resolveApiBaseUrl(): string {
    80|  const envUrl = (process.env.EXPO_PUBLIC_API_BASE_URL ?? process.env.EXPO_PUBLIC_IVX_API_BASE_URL ?? '').trim();
    81|  if (envUrl) {
    82|    return envUrl.replace(/\/$/, '');
    83|  }
    84|  return IVX_CANONICAL_API_BASE_URL;
    85|}
    86|
    87|function redactedSupabaseProjectHint(): string {
    88|  const host = SUPABASE_HOST_HINT;
    89|  if (!host) return 'unknown';
    90|  const parts = host.split('.');
    91|  const ref = parts[0] ?? '';
    92|  if (ref.length <= 4) return host;
    93|  return `${ref.slice(0, 3)}…${ref.slice(-3)}.${parts.slice(1).join('.')}`;
    94|}
    95|
    96|function redactedEasProjectId(value: unknown): string | null {
    97|  if (typeof value !== 'string' || value.length === 0) return null;
    98|  if (value === '00000000-0000-0000-0000-000000000000') return null;
    99|  return `${value.slice(0, 8)}…${value.slice(-4)}`;
   100|}
   101|
   102|/** Epoch ms captured once when the bundle is first evaluated on the device. */
   103|const BUNDLE_BOOT_EPOCH_MS: number = Date.now();
   104|
   105|export function getIVXBuildInfo(): IVXBuildInfo {
   106|  const extra = (Constants.expoConfig?.extra ?? {}) as ExtraShape;
   107|  const runtime = getIVXRuntimeInfo();
   108|  const environment = readEnvironment();
   109|  const commitFull = typeof extra.sourceCommitSha === 'string' && extra.sourceCommitSha.length > 0
   110|    ? extra.sourceCommitSha
   111|    : '';
   112|  const commitShort = commitFull ? commitFull.slice(0, 8) : 'local';
   113|  const buildMarker = readString(extra.buildMarker, '');
   114|  const buildTimestamp = readString(extra.buildTimestamp, '');
   115|  const appVersion = readString(Constants.expoConfig?.version, '0.0.0');
   116|  const apiBaseUrl = resolveApiBaseUrl();
   117|  const supabaseProjectHint = redactedSupabaseProjectHint();
   118|  const easProjectId = redactedEasProjectId(extra.eas?.projectId);
   119|
   120|  let isIdentified = true;
   121|  let unidentifiedReason: string | null = null;
   122|
   123|  if (!commitFull || commitFull === 'local' || commitFull.length < 8) {
   124|    isIdentified = false;
   125|    unidentifiedReason = 'Missing sourceCommitSha in app.config.ts extra. Production builds must embed the Git SHA.';
   126|  } else if (!buildMarker) {
   127|    isIdentified = false;
   128|    unidentifiedReason = 'Missing buildMarker in app.config.ts extra.';
   129|  } else if (!buildTimestamp) {
   130|    isIdentified = false;
   131|    unidentifiedReason = 'Missing buildTimestamp in app.config.ts extra.';
   132|  }
   133|
   134|  return {
   135|    buildMarker: buildMarker || 'unknown-build-marker',
   136|    buildTimestamp: buildTimestamp || 'unknown',
   137|    watchdogPatchVersion: readString(extra.watchdogPatchVersion, 'unknown'),
   138|    frontendDeployMarker: readString(extra.frontendDeployMarker, 'unknown'),
   139|    appVersion,
   140|    commitShort,
   141|    commitFull,
   142|    bundleBootEpochMs: BUNDLE_BOOT_EPOCH_MS,
   143|    environment,
   144|    runtimeKind: runtime.kind,
   145|    apiBaseUrl,
   146|    supabaseProjectHint,
   147|    easProjectId,
   148|    isIdentified,
   149|    unidentifiedReason,
   150|  };
   151|}
   152|
   153|/**
   154| * Throws if the build is unidentified. Call this during app startup in production
   155| * to surface a fatal configuration error instead of shipping an anonymous build.
   156| */
   157|export function assertIVXBuildIdentified(): void {
   158|  if (typeof __DEV__ !== 'undefined' && __DEV__) {
   159|    return;
   160|  }
   161|  const info = getIVXBuildInfo();
   162|  if (!info.isIdentified) {
   163|    throw new Error(info.unidentifiedReason ?? 'Unidentified production build: missing required build identity values.');
   164|  }
   165|}

