   550|async function fetchOwnerAIProxyStatus(audit: IVXOwnerAIConfigAudit): Promise<AIProxyStatusSnapshot> {
   551|  const url = buildOwnerAIProxyStatusUrl(audit);
   552|  if (!url) {
