   566|      url,
   567|      error: 'Owner session token is not hydrated yet.',
   568|    };
   569|  }
   570|
   571|  const controller = new AbortController();
   572|  const timer = setTimeout(() => {
   573|    controller.abort();
   574|  }, AI_FAST_PROXY_TIMEOUT_MS);
   575|
   576|  try {
   577|    const response = await fetch(url, {
   578|      method: 'GET',
   579|      headers: {
   580|        Accept: 'application/json',
   581|        Authorization: `Bearer ${accessToken}`,
   582|      },
   583|      signal: controller.signal,
   584|    });
   585|    const payload = await response.json().catch(() => null) as Record<string, unknown> | null;
   586|    const runtime = isRecord(payload?.runtime) ? payload.runtime : {};
   587|    const runtimeConfigured = runtime.configured === true;
   588|    const deploymentMarker = typeof payload?.deploymentMarker === 'string' ? payload.deploymentMarker : null;
   589|    const model = typeof runtime.model === 'string' ? runtime.model : null;
   590|    const gateway = typeof runtime.gateway === 'string' ? runtime.gateway : null;
   591|    const error = typeof payload?.error === 'string' ? payload.error : typeof payload?.detail === 'string' ? payload.detail : null;
