   595|        status: response.status === 401 || response.status === 403 ? 'blocked' : 'error',
   596|        observedAt: new Date().toISOString(),
   597|        url,
   598|        model,
   599|        gateway,
   600|        configured: false,
   601|        deploymentMarker,
   602|        error: error ?? `Proxy status returned HTTP ${response.status}.`,
   603|      };
   604|    }
   605|
   606|    return {
   607|      status: runtimeConfigured ? 'connected' : 'error',
   608|      observedAt: new Date().toISOString(),
   609|      url,
   610|      model,
   611|      gateway,
   612|      configured: runtimeConfigured,
   613|      deploymentMarker,
   614|      error: runtimeConfigured ? null : 'Proxy route is live, but AI gateway configuration is not ready.',
   615|    };
   616|  } catch (error) {
