     4|/**
     5| * Safe runtime-environment detection for the IVX owner-proof flow.
     6| *
     7| * This NEVER weakens the production admin guard. It only reports *where* the app
     8| * is currently running so the Code Developer Workspace can surface the owner
     9| * build-marker proof flow inside Expo Go / a dev client, while leaving every
    10| * server-side authorization gate exactly as-is.
    11| */
    12|
    13|export type IVXRuntimeKind = 'expo-go' | 'dev-client' | 'standalone' | 'web' | 'unknown';
    14|
    15|export interface IVXRuntimeInfo {
    16|  kind: IVXRuntimeKind;
    17|  /** True when running inside the Expo Go sandbox app. */
    18|  isExpoGo: boolean;
    19|  /** True for any development runtime (Expo Go, dev client, or __DEV__ bundle). */
    20|  isDevRuntime: boolean;
    21|  /** True when this is a shipped production build (App Store / TestFlight / store). */
    22|  isStandalone: boolean;
    23|  isWeb: boolean;
    24|}
    25|
    26|/**
    27| * Resolves the current runtime without throwing. Uses expo-constants
    28| * `executionEnvironment` / `appOwnership`, falling back to `__DEV__` and the
    29| * Platform so it is always safe to call from any screen.
    30| */
    31|export function getIVXRuntimeInfo(): IVXRuntimeInfo {
    32|  const isWeb = Platform.OS === 'web';
    33|
    34|  // executionEnvironment: 'storeClient' (Expo Go), 'standalone' (built app),
    35|  // 'bare' (dev client / bare workflow).
    36|  const executionEnvironment = String(Constants.executionEnvironment ?? '');
    37|  // appOwnership: 'expo' (Expo Go), 'standalone', 'guest' (dev client).
    38|  const appOwnership = String(Constants.appOwnership ?? '');
    39|
    40|  const isExpoGo =
    41|    executionEnvironment === 'storeClient' || appOwnership === 'expo';
    42|  const isStandalone =
    43|    executionEnvironment === 'standalone' || appOwnership === 'standalone';
    44|  const isDevClient =
    45|    !isExpoGo && !isStandalone && (executionEnvironment === 'bare' || appOwnership === 'guest');
    46|
    47|  const devFlag = typeof __DEV__ !== 'undefined' && __DEV__ === true;
    48|
    49|  let kind: IVXRuntimeKind = 'unknown';
    50|  if (isWeb) {
    51|    kind = 'web';
    52|  } else if (isExpoGo) {
    53|    kind = 'expo-go';
    54|  } else if (isStandalone) {
    55|    kind = 'standalone';
    56|  } else if (isDevClient) {
    57|    kind = 'dev-client';
    58|  }
    59|
    60|  return {
    61|    kind,
    62|    isExpoGo,
    63|    isDevRuntime: isExpoGo || isDevClient || devFlag,
    64|    isStandalone,
    65|    isWeb,
    66|  };
    67|}
    68|
    69|/** Convenience: true when the owner-proof flow may be surfaced in this runtime. */
    70|export function isOwnerProofRuntimeAllowed(): boolean {
    71|  const info = getIVXRuntimeInfo();
    72|  // Allow in Expo Go, dev clients, and any dev runtime. Standalone production
    73|  // builds still reach the flow only through the unchanged admin guard.
    74|  return info.isDevRuntime || info.isStandalone || info.isWeb;
