   433|async function withTimeout<T>(operation: () => Promise<T>, timeoutMs: number, label: string, fallbackValue: T): Promise<T> {
   434|  return await new Promise<T>((resolve, reject) => {
   435|    let settled = false;
   436|
   437|    const timeout = setTimeout(() => {
   438|      if (settled) {
   439|        return;
   440|      }
   441|
   442|      settled = true;
   443|      console.log('[Auth] Operation timed out:', label, timeoutMs, 'ms');
   444|      resolve(fallbackValue);
   445|    }, timeoutMs);
   446|
   447|    void operation()
   448|      .then((result) => {
   449|        if (settled) {
   450|          return;
   451|        }
   452|
   453|        settled = true;
   454|        clearTimeout(timeout);
   455|        resolve(result);
   456|      })
   457|      .catch((error) => {
   458|        if (settled) {
   459|          return;
   460|        }
   461|
   462|        settled = true;
   463|        clearTimeout(timeout);
   464|        reject(error);
   465|      });
   466|  });
