function readEnvironment(): IVXBuildInfo['environment'] {
  const runtime = getIVXRuntimeInfo();
  if (typeof __DEV__ !== 'undefined' && __DEV__) {
    return 'development';
  }
  if (runtime.isStandalone) {
    return 'production';
  }
  if (runtime.isExpoGo || runtime.isDevRuntime) {
    return 'development';
  }
  return 'production';
}

